      parentTips: [
        {cn:"\u548c\u5b69\u5b50\u4e00\u8d77\u5206\u6790\u59d3\u6c0f\u53cc\u5173\u7684\u5de7\u5999\uff1a\u6768\u6885\u542b\u201c\u6768\u201d\uff0c\u5b54\u96c0\u542b\u201c\u5b54\u201d\uff0c\u611f\u53d7\u4e2d\u6587\u7684\u5999\u8da3\u3002",en:"Analyze the pun together: yangmei contains \u2018Yang\u2019, kongque contains \u2019Kong\u2019. Appreciate the cleverness of Chinese wordplay."}
      ]
